import{_ as t,o as a,c as n,a2 as r}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Environments","description":"","frontmatter":{},"headers":[],"relativePath":"app/environments.md","filePath":"app/environments.md"}'),o={name:"app/environments.md"};function i(s,e,l,d,p,h){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="environments" tabindex="-1">Environments <a class="header-anchor" href="#environments" aria-label="Permalink to &quot;Environments&quot;">​</a></h1><p>An environment is one deployed git branch of a <a href="/app/projects">project</a>, running as an isolated set of containers with its own services, variables and domains. Deployments are branch-based: the root branch is your production environment, and any other branch can be deployed as a preview environment.</p><h2 id="status-badges" tabindex="-1">Status badges <a class="header-anchor" href="#status-badges" aria-label="Permalink to &quot;Status badges&quot;">​</a></h2><p>The environment page and the project&#39;s environment table show the current state:</p><table tabindex="0"><thead><tr><th>Badge</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Running</strong></td><td>Latest deployment completed; containers are up.</td></tr><tr><td><strong>Deploying</strong></td><td>A deployment is pending or running.</td></tr><tr><td><strong>Failed</strong></td><td>The latest deployment failed.</td></tr><tr><td><strong>Not deployed</strong></td><td>The branch has never been deployed.</td></tr><tr><td><strong>Paused</strong></td><td>The environment was paused; its containers are stopped.</td></tr></tbody></table><h2 id="open-an-environment" tabindex="-1">Open an environment <a class="header-anchor" href="#open-an-environment" aria-label="Permalink to &quot;Open an environment&quot;">​</a></h2><p>From the project overview, click a branch in the <strong>Environments</strong> table. The environment page shows live metrics, status codes, and the <strong>Deployments</strong> table streamed in real time. If a primary domain exists, an <strong>Open</strong> button links to the live site.</p><h2 id="operations" tabindex="-1">Operations <a class="header-anchor" href="#operations" aria-label="Permalink to &quot;Operations&quot;">​</a></h2><p>The header buttons drive the lifecycle of an environment.</p><h3 id="redeploy" tabindex="-1">Redeploy <a class="header-anchor" href="#redeploy" aria-label="Permalink to &quot;Redeploy&quot;">​</a></h3><p><strong>Redeploy</strong> triggers a new deployment of the latest commit on the branch — use it to re-run a deploy with current code or after changing <a href="/app/variables">variables</a>. Confirm in the dialog; you are redirected back to the environment page where the new deploy job streams live.</p><h3 id="pause" tabindex="-1">Pause <a class="header-anchor" href="#pause" aria-label="Permalink to &quot;Pause&quot;">​</a></h3><p><strong>Pause</strong> (previously <em>Disable</em>) stops the environment&#39;s blue/green containers without deleting anything. Data and configuration are kept, and the status switches to <strong>Paused</strong>. A redeploy reactivates it.</p><h3 id="delete" tabindex="-1">Delete <a class="header-anchor" href="#delete" aria-label="Permalink to &quot;Delete&quot;">​</a></h3><p><strong>Delete</strong> stops and removes the environment&#39;s containers, destroys its database volume and deletes the branch&#39;s environment.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Deleting an environment is irreversible — its containers and data volume are destroyed. Pause instead if you only want to stop it temporarily.</p></div><h3 id="sync-environment-data" tabindex="-1">Sync environment data <a class="header-anchor" href="#sync-environment-data" aria-label="Permalink to &quot;Sync environment data&quot;">​</a></h3><p><strong>Sync environment data</strong> pulls data from the running container down to your local setup, so you can work with a copy of the environment&#39;s data.</p><h2 id="example-redeploy-after-changing-a-variable" tabindex="-1">Example: redeploy after changing a variable <a class="header-anchor" href="#example-redeploy-after-changing-a-variable" aria-label="Permalink to &quot;Example: redeploy after changing a variable&quot;">​</a></h2><ol><li>Add or edit an <a href="/app/variables">environment variable</a>.</li><li>Open the environment and click <strong>Redeploy</strong>.</li><li>Confirm — variables are injected into the container on the next deploy.</li><li>Watch the new job complete in the <strong>Deployments</strong> table.</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/deployments">Deployments</a></li><li><a href="/app/domains">Domains &amp; SSL</a></li><li><a href="/app/variables">Environment Variables</a></li><li><a href="/app/projects">Projects</a></li></ul>',22)])])}const u=t(o,[["render",i]]);export{m as __pageData,u as default};
